<!DOCTYPE html>
<html>
<head>
  <title>Personal Expense Tracker</title>
  <style>
    body { font-family: sans-serif; }
    #container { display: flex; }
    #form-area { width: 30%; padding: 10px; border: 1px solid #ccc; }
    #list-area { width: 70%; padding: 10px; border: 1px solid #ccc; overflow-y: auto; }
    .expense { margin-bottom: 5px; }
    .cat-total { font-weight: bold; }
  </style>
</head>
<body>

  <h1>Personal Expense Tracker</h1>

  <div id="container">
    <div id="form-area">
      <form id="expense-form">
        <label for="amount">Amount:</label>
        <input type="number" id="amount" step="0.01"><br><br>

        <label for="category">Category:</label>
        <select id="category">
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select><br><br>

        <label for="date">Date:</label>
        <input type="date" id="date"><br><br>

        <label for="note">Note (optional):</label>
        <textarea id="note"></textarea><br><br>

        <button id="add-expense">Add Expense</button>
        <span id="form-error"></span>
      </form>
    </div>

    <div id="list-area">
      <h2>Expenses</h2>
      <ul class="expenses"></ul>
      <p id="total">0.00</p>
      <div class="cat-totals"></div>

      <label for="filter-category">Category:</label>
      <select id="filter-category">
        <option value="all">All</option>
      </select><br>

      <label for="filter-from">From:</label>
      <input type="date" id="filter-from"><br>

      <label for="filter-to">To:</label>
      <input type="date" id="filter-to"><br>

      <button onclick="applyFilters()">Apply Filters</button>
    </div>
  </div>

  <script>
    const expensesList = document.querySelector('.expenses');
    const totalElement = document.getElementById('total');
    const categoryTotalsContainer = document.querySelector('.cat-totals');
    const expenseForm = document.getElementById('expense-form');
    const amountInput = document.getElementById('amount');
    const categorySelect = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteTextarea = document.getElementById('note');
    const formErrorSpan = document.getElementById('form-error');
    const filterCategorySelect = document.getElementById('filter-category');
    const filterFromInput = document.getElementById('filter-from');
    const filterToInput = document.getElementById('filter-to');

    let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

    function renderExpenses() {
      expensesList.innerHTML = '';
      let visibleExpenses = expenses;

      // Apply filters
      if (filterCategorySelect.value !== 'all') {
        visibleExpenses = expenses.filter(expense => expense.category === filterCategorySelect.value);
      }

      const fromDate = filterFromInput.value || '1900-01-01';
      const toDate = filterToInput.value || '2100-12-31';

      visibleExpenses = visibleExpenses.filter(expense => {
        const expenseDate = new Date(expense.date);
        const fromDateObj = new Date(fromDate);
        const toDateObj = new Date(toDate);
        return expenseDate >= fromDateObj && expenseDate <= toDateObj;
      });

      visibleExpenses.forEach(expense => {
        const li = document.createElement('li');
        li.className = 'expense';
        li.innerHTML = `
          ${expense.amount.toFixed(2)} ${expense.category} - ${expense.date}
          <button class="exp-del" onclick="deleteExpense(${expenses.indexOf(expense)})">Delete</button>
        `;
        expensesList.appendChild(li);
      });

      updateTotal();
      updateCategoryTotals();
    }

    function updateTotal() {
      const total = visibleExpenses.reduce((sum, expense) => sum + expense.amount, 0);
      totalElement.textContent = total.toFixed(2);
    }

    function updateCategoryTotals() {
      const categoryMap = {};
      visibleExpenses.forEach(expense => {
        if (!categoryMap[expense.category]) {
          categoryMap[expense.category] = 0;
        }
        categoryMap[expense.category] += expense.amount;
      });

      for (const category in categoryMap) {
        const li = document.createElement('p');
        li.className = 'cat-total';
        li.setAttribute('data-cat', category);
        li.textContent = `${category}: ${categoryMap[category].toFixed(2)}`;
        categoryTotalsContainer.appendChild(li);
      }
    }

    function addExpense() {
      const amount = parseFloat(amountInput.value);
      const category = categorySelect.value;
      const date = dateInput.value;
      const note = noteTextarea.value || '';

      if (isNaN(amount) || amount <= 0 || !date) {
        formErrorSpan.textContent = 'Please enter a valid amount and date.';
        return;
      }

      const newExpense = { amount, category, date, note };
      expenses.push(newExpense);
      localStorage.setItem('expenses', JSON.stringify(expenses));
      renderExpenses();
      formErrorSpan.textContent = '';
      amountInput.value = '';
    }

    function deleteExpense(index) {
      expenses.splice(index, 1);
      localStorage.setItem('expenses', JSON.stringify(expenses));
      renderExpenses();
    }

    function applyFilters() {
        renderExpenses();
    }


    // Initial load
    renderExpenses();
  </script>

</body>
</html>
